create table if not exists audit_events (
  id text primary key,
  action text not null,
  created_at text not null default current_timestamp
);

export interface Env {
  DB: D1Database;
}

export async function listAuditEvents(env: Env) {
  return env.DB.prepare("select id, action, created_at from audit_events order by created_at desc limit 50").all();
}

const checks = [
  "Install provider package and configure env",
  "Run the local example path",
  "Add auth, retries, and audit events before production",
];

export default function CloudflareD1Page() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Cloudflare D1</h1>
        <p className="text-muted-foreground">SQLite at the edge with explicit bindings and migration files.</p>
      </div>
      <div className="grid gap-3">
        {checks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
